phase1.code:
using UnityEngine;

public class ProjectFullPlaythrough : MonoBehaviour
{
    [Header("Levels")]
    public int currentLevel = 1;
    public int totalLevels = 3;

    [Header("Game State")]
    public int score = 0;
    public int lives = 3;
    public bool gameComplete = false;

    void Start()
    {
        Debug.Log("=== Project: Full Playthrough Ready ===");
        Debug.Log("🎯 Goal: Build a complete, playable game");

        Debug.Log("\n--- Level Design ---");
        Debug.Log("Level 1: Introduction (move, jump, collect)");
        Debug.Log("Level 2: Challenge (enemies, obstacles)");
        Debug.Log("Level 3: Boss (all mechanics combined)");

        Debug.Log("\n--- Polish Checklist ---");
        Debug.Log("✅ All levels playable");
        Debug.Log("✅ Progression works (Level 1 → Level 2 → Level 3)");
        Debug.Log("✅ Game over restart");
        Debug.Log("✅ Win state");
        Debug.Log("✅ Sound effects");
        Debug.Log("✅ Particles");
        Debug.Log("✅ UI/HUD");
        Debug.Log("✅ Save/Load");
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.L))
        {
            NextLevel();
        }
        if (Input.GetKeyDown(KeyCode.R))
        {
            RestartGame();
        }
    }

    public void NextLevel()
    {
        currentLevel++;
        if (currentLevel > totalLevels)
        {
            CompleteGame();
        }
        else
        {
            Debug.Log("Loading Level " + currentLevel);
            // UnityEngine.SceneManagement.SceneManager.LoadScene("Level" + currentLevel);
        }
    }

    public void CompleteGame()
    {
        gameComplete = true;
        Debug.Log("🎉 Game Complete!");
        Debug.Log("Final Score: " + score);
        // Show credits
    }

    public void RestartGame()
    {
        currentLevel = 1;
        score = 0;
        lives = 3;
        gameComplete = false;
        Debug.Log("Game restarted!");
        // UnityEngine.SceneManagement.SceneManager.LoadScene("Level1");
    }
}

